<?php
namespace App\Modules\Hr\Compensation\Models;use App\Modules\Hr\Core\Traits\BelongsToLegalEntity;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;
class HrSalaryRecord extends Model{use BelongsToLegalEntity;protected $fillable=['legal_entity_id','employee_id','salary_band_id','version','gross_salary_encrypted','currency','effective_from','status','change_reason','created_by','approved_by','approved_at'];protected $hidden=['gross_salary_encrypted'];protected function casts():array{return ['gross_salary_encrypted'=>'encrypted','effective_from'=>'date','approved_at'=>'datetime','version'=>'integer'];}public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);}public function band():BelongsTo{return $this->belongsTo(HrSalaryBand::class,'salary_band_id');}public function grossSalary():float{return(float)$this->gross_salary_encrypted;}}
